from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""

    # Group triples by subject to handle multiple facts about the same entity
    entity_data = {}
    for triple in triples:
        if triple.subject not in entity_data:
            entity_data[triple.subject] = []
        entity_data[triple.subject].append(triple)

    # Find the main subject (entity with most information)
    main_subject = max(entity_data.keys(), key=lambda x: len(entity_data[x]))
    subject_triples = entity_data[main_subject]

    # Build sentence parts based on predicate types
    parts = []
    related_info = []

    for triple in subject_triples:
        pred = triple.predicate
        obj = triple.object

        if pred == 'country':
            parts.append(f"is located in {obj}")
        elif pred == 'city':
            parts.append(f"is based in {obj}")
        elif pred == 'industry':
            parts.append(f"operates in the {obj}")
        elif pred == 'foundingDate':
            parts.append(f"was founded in {obj}")
        elif pred == 'type':
            parts.append(f"is a {obj}")
        elif pred == 'leader' or pred == 'keyPerson':
            parts.append(f"with {obj} as a key person")
        elif pred == 'numberOfEmployees':
            parts.append(f"employs {obj} people")
        elif pred == 'revenue':
            parts.append(f"generates {obj} in revenue")
        elif pred == 'operatingIncome':
            parts.append(f"has operating income of {obj}")
        elif pred == 'netIncome':
            parts.append(f"reports net income of {obj}")
        elif pred == 'product':
            parts.append(f"offers {obj}")
        elif pred == 'service':
            parts.append(f"provides {obj}")
        elif pred == 'location':
            parts.append(f"located in {obj}")
        elif pred == 'parentCompany':
            parts.append(f"subsidiary of {obj}")
        elif pred == 'capital':
            related_info.append(f"capital is {obj}")
        elif pred == 'officialLanguage':
            related_info.append(f"official language is {obj}")
        elif pred == 'populationTotal':
            related_info.append(f"population of {obj}")
        elif pred == 'areaTotal':
            related_info.append(f"covers {obj}")
        else:
            # Generic handling for remaining predicates
            formatted_pred = pred.replace('Date', 'date').replace('Income', 'income')
            parts.append(f"{formatted_pred} is {obj}")

    # Build the main sentence
    if parts:
        sentence = f"{main_subject} " + ", ".join(parts)
    else:
        sentence = main_subject

    # Add related information if available
    if related_info:
        sentence += ", where " + ", ".join(related_info)

    return sentence

# EVOLVE-BLOCK-END

